            if isinstance(v, datetime):
                if maxd is None or v > maxd: maxd = v
            elif isinstance(v, str) and len(v) >= 10 and v[4]=='-' and v[7]=='-':
                try:
                    d = datetime.strptime(v[:10],'%Y-%m-%d')
                    if maxd is None or d > maxd: maxd = d
                except: pass
    print(f'{s}\t{maxd.date() if maxd else \"?\"}')"

